import React, { useState } from 'react';
import { Store, MapPin, Plus, Trash2, Tag } from 'lucide-react';

const Dashboard = () => {
  const [locales, setLocales] = useState(() => JSON.parse(localStorage.getItem('mis-locales') || "[]"));
  const [nuevoLocal, setNuevoLocal] = useState({ nombre: '', direccion: '' });

  const agregarLocal = (e) => {
    e.preventDefault();
    if (!nuevoLocal.nombre || !nuevoLocal.direccion) return;

    const localCompleto = { ...nuevoLocal, id: Date.now() };
    const actualizados = [...locales, localCompleto];
    setLocales(actualizados);
    localStorage.setItem('mis-locales', JSON.stringify(actualizados));
    setNuevoLocal({ nombre: '', direccion: '' }); // Reset solo de nombre y dirección
  };

  const eliminarLocal = (id) => {
    const filtrados = locales.filter(l => l.id !== id);
    setLocales(filtrados);
    localStorage.setItem('mis-locales', JSON.stringify(filtrados));
    localStorage.removeItem(`ofertas-local-${id}`);
  };

  return (
    <div style={container}>
      <h1 style={title}><Store size={32} /> Panel de Mis Sucursales</h1>

      {/* FORMULARIO SIMPLIFICADO: Solo Nombre y Dirección */}
      <form onSubmit={agregarLocal} style={formCard}>
        <h2 style={formTitle}>Registrar Nueva Sucursal</h2>
        <div style={inputGroup}>
          <div style={field}>
            <label style={label}>Nombre del Local</label>
            <input 
              style={input}
              type="text" 
              placeholder="Ej: Supermercado Central"
              value={nuevoLocal.nombre}
              onChange={(e) => setNuevoLocal({...nuevoLocal, nombre: e.target.value})}
            />
          </div>
          <div style={field}>
            <label style={label}>Dirección Exacta</label>
            <input 
              style={input}
              type="text" 
              placeholder="Ej: Av. Alem 123"
              value={nuevoLocal.direccion}
              onChange={(e) => setNuevoLocal({...nuevoLocal, direccion: e.target.value})}
            />
          </div>
        </div>
        <button type="submit" style={btnSubmit}>
          <Plus size={20} /> Crear Sucursal
        </button>
      </form>

      {/* LISTADO DE SUCURSALES */}
      <div style={grid}>
        {locales.map(local => (
          <div key={local.id} style={card}>
            <div style={cardHeader}>
              <h3 style={{margin: 0}}>{local.nombre}</h3>
              <button onClick={() => eliminarLocal(local.id)} style={btnDelete} title="Eliminar local">
                <Trash2 size={18} />
              </button>
            </div>
            <p style={cardText}><MapPin size={16} /> {local.direccion}</p>
            
            <button 
              style={btnOfertas} 
              onClick={() => window.location.href = `/ofertas/${local.id}`}
            >
              <Tag size={18} /> Gestionar Ofertas
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

/* --- ESTILOS LIMPIOS --- */
const container = { padding: '40px 8%', background: '#f8fafc', minHeight: '100vh' };
const title = { display: 'flex', alignItems: 'center', gap: '15px', color: '#1e293b', marginBottom: '30px' };
const formCard = { background: 'white', padding: '30px', borderRadius: '20px', boxShadow: '0 4px 20px rgba(0,0,0,0.05)', marginBottom: '40px' };
const formTitle = { fontSize: '1.2rem', marginBottom: '20px', color: '#64748b' };
const inputGroup = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', marginBottom: '20px' };
const field = { display: 'flex', flexDirection: 'column', gap: '8px' };
const label = { fontSize: '0.9rem', fontWeight: 'bold', color: '#475569' };
const input = { padding: '12px', borderRadius: '10px', border: '1px solid #e2e8f0', outline: 'none', fontSize: '1rem' };
const btnSubmit = { background: '#e67e22', color: 'white', border: 'none', padding: '12px 25px', borderRadius: '12px', cursor: 'pointer', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '10px' };

const grid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '25px' };
const card = { background: 'white', padding: '25px', borderRadius: '20px', border: '1px solid #e2e8f0', boxShadow: '0 4px 12px rgba(0,0,0,0.02)' };
const cardHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '15px' };
const cardText = { color: '#64748b', fontSize: '0.95rem', display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '20px' };
const btnOfertas = { width: '100%', padding: '12px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px', fontWeight: 'bold' };
const btnDelete = { background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', padding: '5px' };

export default Dashboard;
